const bookingData = $('Supabase → Booking Data').first().json;
const analysis = $input.first().json.content?.[0]?.text || '{}';

let parsed = {};
try {
  const cleaned = analysis.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  parsed = { raw_analysis: analysis };
}

return [{ json: {
  status: 'completed',
  workflow: '17_booking_analytics',
  data_source: 'get_daily_stats',
  analysis: parsed,
  completedAt: new Date().toISOString()
} }];
